+        return string.Join(" ", scored);
+    }
+
+    private static List<string> SplitSentences(string text)
+    {
+        return SentenceRegex()
+            .Split(text)
+            .Select(s => s.Trim())
+            .Where(s => s.Length > 0)
+            .ToList();
+    }
+
+    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
+    {
+        var freqs = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in TokenizeWords(sentence))
+            {
+                if (!StopWords.Contains(word))
+                    freqs[word] = freqs.GetValueOrDefault(word) + 1;
+            }
+        }
+        return freqs;
+    }
+
+    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFreqs)
+    {
+        var words = TokenizeWords(sentence);
+        if (words.Count == 0) return 0;
+
+        double total = words
+            .Where(w => !StopWords.Contains(w))
+            .Sum(w => wordFreqs.GetValueOrDefault(w));
+
+        return total / words.Count;
+    }
+
+    private static List<string> TokenizeWords(string text)
+    {
+        return WordRegex()
+            .Matches(text)
+            .Select(m => m.Value)
+            .ToList();
+    }
